// orchestrate-phase1 — Step 1: Resolve Runtime Config
// Validates all required environment variables and assembles the runtime config.
// Any CONFIG_MISSING error halts the entire chain here — before any subworkflow runs.
//
// TRIGGER INPUT (manual run):
//   { "intake_payload": { "project_id": "...", ... } }
//
// CLOUD MODE (n8n Cloud): process and require('fs') are not available.
// Pass a smoke_test_config in the trigger input to supply config values:
//   {
//     "intake_payload": { "project_id": "...", ... },
//     "smoke_test_config": {
//       "STORE_OS_OPENAI_CREDENTIAL_NAME": "OpenAI account",
//       "STORE_OS_SHOPIFY_CREDENTIAL_NAME": "Shopify account",
//       "STORE_OS_SHOPIFY_SHOP_URL": "my-store.myshopify.com",
//       "STORE_OS_LLM_MODEL": "gpt-4o",
//       "STORE_OS_ENV": "dev",
//       "STORE_OS_SHOPIFY_API_VERSION": "2024-01"
//     }
//   }

// Cloud-mode detection: n8n Cloud exposes neither require('fs') nor process
let cloudMode = false;
try { require('fs'); } catch (_e) { cloudMode = true; }
if (typeof process === 'undefined') { cloudMode = true; }

// Extract trigger input early — needed for cloud config fallback
const triggerInput = $input.first().json;

// Cloud-safe env accessor
// Self-hosted: reads from process.env
// Cloud:       reads from trigger input's smoke_test_config object
const smokeConfig = (cloudMode && triggerInput.smoke_test_config) ? triggerInput.smoke_test_config : {};
const getEnv = cloudMode
  ? (key) => { const v = smokeConfig[key]; return (v && String(v).trim()) ? String(v).trim() : null; }
  : (key) => { const v = process.env[key]; return (v && v.trim()) ? v.trim() : null; };

// Core vars required in both cloud and self-hosted modes
const REQUIRED_ENV_VARS_CORE = [
  'STORE_OS_OPENAI_CREDENTIAL_NAME',
  'STORE_OS_SHOPIFY_CREDENTIAL_NAME',
  'STORE_OS_SHOPIFY_SHOP_URL',
  'STORE_OS_LLM_MODEL',
  'STORE_OS_ENV',
  'STORE_OS_SHOPIFY_API_VERSION',
];

// Filesystem vars only required in self-hosted mode
const REQUIRED_ENV_VARS_FS = ['STORE_OS_PROJECT_ROOT', 'STORE_OS_AJV_SCHEMA_PATH'];

const REQUIRED_ENV_VARS = cloudMode
  ? REQUIRED_ENV_VARS_CORE
  : [...REQUIRED_ENV_VARS_CORE, ...REQUIRED_ENV_VARS_FS];

const ALLOWED_ENVS = ['dev', 'staging', 'production'];

const missing = REQUIRED_ENV_VARS.filter((v) => !getEnv(v));
if (missing.length > 0) {
  throw new Error(
    'CONFIG_MISSING: Required environment variables not set: ' + missing.join(', ') +
    (cloudMode
      ? '. In n8n Cloud, pass these as smoke_test_config in the trigger input JSON.'
      : '. Configure them in n8n Settings > Variables or the n8n process environment.')
  );
}

const env = getEnv('STORE_OS_ENV');
if (!ALLOWED_ENVS.includes(env)) {
  throw new Error(`CONFIG_MISSING: STORE_OS_ENV must be one of: ${ALLOWED_ENVS.join(', ')}. Got: "${env}"`);
}

// Filesystem path validation — self-hosted only
// CLOUD SKIP: fs.existsSync requires local filesystem, not available in n8n Cloud
let fs;
let projectRoot = null;
let ajvSchemaPath = null;

if (!cloudMode) {
  fs = require('fs');
  projectRoot = getEnv('STORE_OS_PROJECT_ROOT');
  if (!fs.existsSync(projectRoot)) {
    throw new Error(`CONFIG_MISSING: STORE_OS_PROJECT_ROOT does not exist: ${projectRoot}`);
  }

  ajvSchemaPath = getEnv('STORE_OS_AJV_SCHEMA_PATH');
  if (!fs.existsSync(ajvSchemaPath)) {
    throw new Error(`CONFIG_MISSING: STORE_OS_AJV_SCHEMA_PATH does not exist: ${ajvSchemaPath}`);
  }
}

const runtimeConfig = {
  env,
  project_root:            projectRoot,
  openai_credential_name:  getEnv('STORE_OS_OPENAI_CREDENTIAL_NAME'),
  shopify_credential_name: getEnv('STORE_OS_SHOPIFY_CREDENTIAL_NAME'),
  shopify_shop_url:        getEnv('STORE_OS_SHOPIFY_SHOP_URL'),
  llm_model:               getEnv('STORE_OS_LLM_MODEL'),
  shopify_api_version:     getEnv('STORE_OS_SHOPIFY_API_VERSION'),
  ajv_schema_path:         ajvSchemaPath,
  backup_root:             getEnv('STORE_OS_BACKUP_ROOT'),
  resolved_at:             new Date().toISOString(),
  cloud_mode:              cloudMode,
};

if (cloudMode) {
  console.warn(
    'CLOUD_MODE: Running in n8n Cloud compatibility mode. ' +
    'Config read from trigger input smoke_test_config. ' +
    'Filesystem operations are disabled for the entire Phase 1 chain. ' +
    'No artifact persistence or schema validation will occur.'
  );
}

// Extract intake_payload from the trigger input
const intakePayload = triggerInput.intake_payload;

if (!intakePayload || !intakePayload.project_id) {
  throw new Error(
    'MISSING_INPUT: intake_payload with project_id is required. ' +
    'Provide it as the manual trigger input JSON: { "intake_payload": { "project_id": "...", ... } }'
  );
}

return [{
  json: {
    runtime_config:  runtimeConfig,
    intake_payload:  intakePayload,
    chain_step:      'resolve-runtime-config',
    status:          'SUCCESS',
  },
}];

// orchestrate-phase1 — Intake HALT
// Reached when intake-store-input returns a non-SUCCESS status.
// Logs the failure. The chain stops here (no further nodes connected).

const input = $input.first().json;
const errorMsg = `CHAIN_HALT: intake-store-input failed. Status: ${input.status}. Check the intake-store-input execution for details.`;
console.error(errorMsg);
throw new Error(errorMsg);

// orchestrate-phase1 — Import HALT
const input   = $input.first().json;
const errorMsg = `CHAIN_HALT: import-shopify-data failed. Status: ${input.status}.`;
console.error(errorMsg);
throw new Error(errorMsg);

// orchestrate-phase1 — Bridge: Prepare build-store-profile input
// import-shopify-data returns its own output.
// We re-attach normalized_intake_payload from intake-store-input
// so that build-store-profile has both upstream inputs.
//
// CLOUD MODE: import-shopify-data returns shopify_import inline (no disk write).
// We pass it through here so build-store-profile can read it from input
// instead of from disk. In self-hosted mode, shopify_import is not included
// (build-store-profile reads it from disk directly).

const importOutput = $input.first().json;
const intakeOutput = $node['Run intake-store-input'].json;

const output = {
  project_id:                 importOutput.project_id,
  runtime_config:             importOutput.runtime_config,
  normalized_intake_payload:  intakeOutput.normalized_intake_payload,
  import_summary:             importOutput.import_summary,
  chain_step:                 'pre-build-store-profile',
};

// In cloud mode, pass shopify_import inline so build-store-profile
// can read it from the trigger input instead of from disk.
if (importOutput.cloud_mode && importOutput.shopify_import) {
  output.shopify_import = importOutput.shopify_import;
}

return [{ json: output }];

// orchestrate-phase1 — Profile HALT
const input    = $input.first().json;
const errorMsg = `CHAIN_HALT: build-store-profile failed. Status: ${input.status}.`;
console.error(errorMsg);
throw new Error(errorMsg);

// orchestrate-phase1 — Phase 1 Chain Done
// All Phase 1 workflows completed successfully.
// Assembles a summary and passes forward data needed for Phase 2 (build-market-intelligence).
//
// SELF-HOSTED: Reads final checkpoint from disk to include in summary.
// CLOUD MODE: Checkpoint read is skipped (no filesystem). Summary assembled
//             from upstream outputs. store_profile, runtime_config,
//             normalized_intake_payload, and shopify_import (catalog context)
//             are all passed forward inline.

const profileOutput = $input.first().json;

// Cloud-mode detection — n8n Cloud does not allow require('fs')
let fs, path;
let cloudMode = profileOutput.cloud_mode || false;
if (!cloudMode) {
  try {
    fs   = require('fs');
    path = require('path');
  } catch (_e) {
    cloudMode = true;
  }
}

const projectId   = profileOutput.project_id;
const projectRoot = cloudMode ? null : profileOutput.runtime_config.project_root;

// Read final checkpoint to include in summary — self-hosted only
let checkpoint = null;
if (!cloudMode) {
  try {
    const cpPath = path.join(projectRoot, projectId, '.runtime', 'checkpoint.json');
    if (fs.existsSync(cpPath)) {
      checkpoint = JSON.parse(fs.readFileSync(cpPath, 'utf8'));
    }
  } catch { /* non-fatal */ }
}

// Collect upstream data needed for Phase 2
const intakeOutput = $node['Run intake-store-input'].json;
const importOutput = $node['Run import-shopify-data'].json;

const summary = {
  status:               'PHASE_1_COMPLETE',
  project_id:           projectId,
  artifact_written:     profileOutput.artifact_path,
  completed_at:         new Date().toISOString(),
  next_phase:           'Phase 2 — Market Intelligence (build-market-intelligence)',
  checkpoint_status:    checkpoint ? checkpoint.chain_status : (cloudMode ? 'cloud-mode-no-checkpoint' : 'unknown'),
  notes:                (profileOutput.notes || []).filter(Boolean),
  cloud_mode:           cloudMode,
  cloud_warnings:       cloudMode ? (profileOutput.cloud_warnings || ['No artifact persistence occurred — cloud mode active']) : [],
  message:              cloudMode
    ? [
        `Phase 1 chain completed (cloud mode) for project: ${projectId}`,
        'No artifacts were written to disk. store_profile is available in this output.',
        'Continuing to Phase 2: build-market-intelligence.',
      ].join(' | ')
    : [
        `Phase 1 chain completed for project: ${projectId}`,
        `store-profile.json written to: ${profileOutput.artifact_path}`,
        'Continuing to Phase 2: build-market-intelligence.',
      ].join(' | '),
  // Pass forward for Phase 2
  runtime_config:              profileOutput.runtime_config,
  store_profile:               profileOutput.store_profile,
  normalized_intake_payload:   intakeOutput.normalized_intake_payload,
};

// In cloud mode, pass shopify_import inline for catalog context in market intel
if (cloudMode && importOutput && importOutput.shopify_import) {
  summary.shopify_import = importOutput.shopify_import;
}

return [{ json: summary }];

// orchestrate-phase1 — Bridge: Prepare build-market-intelligence input
// Assembles the input payload for the build-market-intelligence subworkflow.
// build-market-intelligence expects: project_id, store_profile,
// normalized_intake_payload, runtime_config, and optionally shopify_import.

const phase1Output = $input.first().json;

const output = {
  project_id:                 phase1Output.project_id,
  runtime_config:             phase1Output.runtime_config,
  store_profile:              phase1Output.store_profile,
  normalized_intake_payload:  phase1Output.normalized_intake_payload,
  chain_step:                 'pre-build-market-intelligence',
};

// Pass shopify_import inline for catalog context (present in cloud mode
// and when import-shopify-data forwarded it through Phase 1 Complete)
if (phase1Output.shopify_import) {
  output.shopify_import = phase1Output.shopify_import;
}

return [{ json: output }];

// orchestrate-phase1 — Market Intelligence HALT
const input    = $input.first().json;
const errorMsg = `CHAIN_HALT: build-market-intelligence failed. Status: ${input.status}.`;
console.error(errorMsg);
throw new Error(errorMsg);

// orchestrate-phase1 — Phase 2 Complete
// build-market-intelligence succeeded.
// Returns a summary for the operator and carries all data forward for Phase 3 (build-brand-positioning).
//
// CLOUD MODE: market_intelligence is returned inline (no disk artifact).
// SELF-HOSTED: artifact_path points to market-intelligence.json on disk.
//              market_intelligence object is also passed inline for Phase 3.

const miOutput = $input.first().json;
const cloudMode = miOutput.cloud_mode || false;

// Gather upstream data needed for Phase 3 (brand positioning)
const phase1Output = $node['Phase 1 Complete'].json;

const summary = {
  status:           'PHASE_2_COMPLETE',
  project_id:       miOutput.project_id,
  artifact_written: miOutput.artifact_path,
  completed_at:     new Date().toISOString(),
  next_phase:       'Phase 3 — Brand Positioning (build-brand-positioning)',
  cloud_mode:       cloudMode,
  cloud_warnings:   miOutput.cloud_warnings || [],
  notes:            (miOutput.notes || []).filter(Boolean),
  message:          cloudMode
    ? [
        `Phase 2 chain completed (cloud mode) for project: ${miOutput.project_id}`,
        'No artifacts were written to disk. market_intelligence is available in this output.',
        'Continuing to Phase 3: build-brand-positioning.',
      ].join(' | ')
    : [
        `Phase 2 chain completed for project: ${miOutput.project_id}`,
        `market-intelligence.json written to: ${miOutput.artifact_path}`,
        'Continuing to Phase 3: build-brand-positioning.',
      ].join(' | '),
  // Pass forward for Phase 3 (always — market_intelligence flows inline in both modes)
  runtime_config:             miOutput.runtime_config || phase1Output.runtime_config,
  store_profile:              phase1Output.store_profile,
  normalized_intake_payload:  phase1Output.normalized_intake_payload,
  market_intelligence:        miOutput.market_intelligence,
};

return [{ json: summary }];

// orchestrate-phase1 — Bridge: Prepare build-brand-positioning input
// Assembles the input payload for the build-brand-positioning subworkflow.
// build-brand-positioning expects: project_id, store_profile, market_intelligence,
// normalized_intake_payload, and runtime_config.
//
// market_intelligence flows inline in both cloud and self-hosted modes
// (forwarded from build-market-intelligence output through Phase 2 Complete).

const phase2Output = $input.first().json;

const output = {
  project_id:                 phase2Output.project_id,
  runtime_config:             phase2Output.runtime_config,
  store_profile:              phase2Output.store_profile,
  normalized_intake_payload:  phase2Output.normalized_intake_payload,
  market_intelligence:        phase2Output.market_intelligence,
  chain_step:                 'pre-build-brand-positioning',
};

return [{ json: output }];

// orchestrate-phase1 — Brand Positioning HALT
const input    = $input.first().json;
const errorMsg = `CHAIN_HALT: build-brand-positioning failed. Status: ${input.status}.`;
console.error(errorMsg);
throw new Error(errorMsg);

// orchestrate-phase1 — Phase 3 Complete
// build-brand-positioning succeeded.
// Returns a summary for the operator. Terminal node for now.
//
// CLOUD MODE: brand_positioning is returned inline (no disk artifact).
// SELF-HOSTED: artifact_path points to brand-positioning.json on disk.

const bpOutput = $input.first().json;
const cloudMode = bpOutput.cloud_mode || false;

const summary = {
  status:           'PHASE_3_COMPLETE',
  project_id:       bpOutput.project_id,
  artifact_written: bpOutput.artifact_path,
  completed_at:     new Date().toISOString(),
  next_phase:       'Phase 4+ — Competitor Clusters and downstream planning (not yet implemented)',
  cloud_mode:       cloudMode,
  cloud_warnings:   bpOutput.cloud_warnings || [],
  notes:            (bpOutput.notes || []).filter(Boolean),
  message:          cloudMode
    ? [
        `Phase 3 chain completed (cloud mode) for project: ${bpOutput.project_id}`,
        'No artifacts were written to disk. brand_positioning is available in this output.',
        'Next: build-competitor-clusters (Phase 4+ — not yet implemented).',
      ].join(' | ')
    : [
        `Phase 3 chain completed for project: ${bpOutput.project_id}`,
        `brand-positioning.json written to: ${bpOutput.artifact_path}`,
        'Next: build-competitor-clusters (Phase 4+ — not yet implemented).',
      ].join(' | '),
};

// Carry brand_positioning forward for inspection
if (bpOutput.brand_positioning) {
  summary.brand_positioning = bpOutput.brand_positioning;
}

return [{ json: summary }];
